SELECT 
FROM project p
LEFT JOIN customer c ON c.id = p.customer_id AND c.deleted = 0
LEFT JOIN sys_user u ON u.id = p.pm_id AND u.deleted = 0

    p.deleted = 0

        AND (p.project_name LIKE CONCAT('%', #{query.keyword}, '%')
          OR p.project_code LIKE CONCAT('%', #{query.keyword}, '%'))


        AND p.status = #{query.status}


        AND p.pm_id = #{query.pmId}


        AND p.customer_id = #{query.customerId}


        AND p.execute_mode = #{query.executeMode}


        AND p.priority = #{query.priority}


        AND p.region = #{query.region}


        AND p.product_line = #{query.productLine}


        AND p.project_type = #{query.projectType}


ORDER BY p.create_time DESC

SELECT p.status AS status, COUNT(1) AS cnt, p.id AS id, p.project_code AS projectCode, p.project_name AS projectName, p.priority AS priority, p.progress_pct AS progressPct, p.pm_id AS pmId, u.real_name AS pmName, p.customer_id AS customerId, c.customer_name AS customerName, p.execute_mode AS executeMode FROM project p LEFT JOIN customer c ON c.id = p.customer_id AND c.deleted = 0 LEFT JOIN sys_user u ON u.id = p.pm_id AND u.deleted = 0
p.deleted = 0
AND p.pm_id = #{query.pmId}
AND p.customer_id = #{query.customerId}
AND p.execute_mode = #{query.executeMode}
AND p.priority = #{query.priority}
AND p.region = #{query.region}
ORDER BY p.status, p.priority
